return items.map(item => {
  const stock = Number(item.json.Current_Stock);
  const demand = Number(item.json.Daily_Demand);
  const safety = Number(item.json.Safety_Stock);
  const leadTime = Number(item.json.Lead_Time_Days);

  // Days until stockout
  const daysToStockout = stock / demand;

  // Reorder quantity
  const reorderQty =
    (demand * leadTime) + safety - stock;

  // Risk Level
  let riskLevel;

  if (daysToStockout < 3) {
    riskLevel = "Critical";
  } else if (daysToStockout < 7) {
    riskLevel = "High";
  } else if (daysToStockout < 14) {
    riskLevel = "Medium";
  } else {
    riskLevel = "Low";
  }

  // Inventory Value
  const inventoryValue =
    stock * Number(item.json.Unit_Cost_USD || item.json.Unit_Cost);

  item.json.Days_To_Stockout =
    Number(daysToStockout.toFixed(2));

  item.json.Reorder_Quantity =
    Math.max(0, Math.ceil(reorderQty));

  item.json.Risk_Level =
    riskLevel;

  item.json.Inventory_Value_USD =
    Number(inventoryValue.toFixed(2));

  return item;
});

return items.map(item => {

    // Read values
    const stock = Number(item.json.Current_Stock);
    const demand = Number(item.json.Daily_Demand);

    // Forecast demand
    const forecast7 = demand * 7;
    const forecast30 = demand * 30;

    // Predicted stock
    const predicted7 = stock - forecast7;
    const predicted30 = stock - forecast30;

    // Save calculations
    item.json.Forecast_7_Days = forecast7;
    item.json.Forecast_30_Days = forecast30;

    item.json.Predicted_Stock_7_Days = predicted7;
    item.json.Predicted_Stock_30_Days = predicted30;

    // Forecast Status & Risk Level
    if (predicted7 < 0) {

        item.json.Forecast_Status = "Stockout Expected Within 7 Days";
        item.json.Risk_Level = "Critical";

    } else if (predicted30 < 0) {

        item.json.Forecast_Status = "Stockout Expected Within 30 Days";
        item.json.Risk_Level = "High";

    } else {

        item.json.Forecast_Status = "Inventory Sufficient";
        item.json.Risk_Level = "Low";

    }

    return item;

});

return items.map(item => {

    // ============================
    // Read values
    // ============================
    const demand = Number(item.json.Daily_Demand);
    const stock = Number(item.json.Current_Stock);
    const safety = Number(item.json.Safety_Stock);
    const leadTime = Number(item.json.Lead_Time_Days);
    const unitCost = Number(item.json.Unit_Cost);

    // ============================
    // Procurement Calculations
    // ============================
    const leadTimeDemand = demand * leadTime;

    const suggestedOrderQty = Math.max(
        0,
        leadTimeDemand + safety - stock
    );

    const estimatedOrderValue =
        suggestedOrderQty * unitCost;

    // ============================
    // Purchase Priority
    // ============================
    let purchasePriority;

    if (item.json.Forecast_Status === "Stockout Expected Within 7 Days") {

        purchasePriority = "Critical";

    } else if (item.json.Forecast_Status === "Stockout Expected Within 30 Days") {

        purchasePriority = "High";

    } else {

        purchasePriority = "Normal";

    }

    // ============================
    // Procurement Action
    // ============================
    let procurementAction;

    if (purchasePriority === "Critical") {

        procurementAction = "Immediate Reorder";

    } else if (purchasePriority === "High") {

        procurementAction = "Reorder This Week";

    } else {

        procurementAction = "Monitor Inventory";

    }

    // ============================
    // Supplier Action
    // ============================
    let supplierAction;

    if (purchasePriority === "Critical") {

        supplierAction = "Expedite Supplier";

    } else if (purchasePriority === "High") {

        supplierAction = "Standard Purchase";

    } else {

        supplierAction = "No Action";

    }

    // ============================
    // Buyer Recommendation
    // ============================
    let buyerRecommendation;

    if (purchasePriority === "Critical") {

        buyerRecommendation = "Raise Purchase Order Today";

    } else if (purchasePriority === "High") {

        buyerRecommendation = "Schedule Purchase This Week";

    } else {

        buyerRecommendation = "Continue Monitoring";

    }

    // ============================
    // Procurement Status
    // ============================
    let procurementStatus;

    if (suggestedOrderQty > 0) {

        procurementStatus = "Approval Required";

    } else {

        procurementStatus = "No Purchase Required";

    }

    // ============================
    // Procurement Category
    // ============================
    let procurementCategory;

    if (purchasePriority === "Critical") {

        procurementCategory = "Emergency Purchase";

    } else if (purchasePriority === "High") {

        procurementCategory = "Planned Purchase";

    } else {

        procurementCategory = "Routine Monitoring";

    }

    // ============================
    // Save Results
    // ============================
    item.json.Lead_Time_Demand = leadTimeDemand;
    item.json.Suggested_Order_Qty = Math.ceil(suggestedOrderQty);
    item.json.Estimated_Order_Value = Number(estimatedOrderValue.toFixed(2));

    item.json.Purchase_Priority = purchasePriority;
    item.json.Procurement_Action = procurementAction;
    item.json.Supplier_Action = supplierAction;

    item.json.Buyer_Recommendation = buyerRecommendation;
    item.json.Procurement_Status = procurementStatus;
    item.json.Procurement_Category = procurementCategory;

    return item;

});

const itemsData = items.map(i => i.json);

const totalProducts = itemsData.length;

const criticalProducts =
itemsData.filter(i => i.Purchase_Priority === "Critical").length;

const highProducts =
itemsData.filter(i => i.Purchase_Priority === "High").length;

const stockout7 =
itemsData.filter(i =>
i.Forecast_Status === "Stockout Expected Within 7 Days").length;

const stockout30 =
itemsData.filter(i =>
i.Forecast_Status === "Stockout Expected Within 30 Days").length;

const emergencyPurchases =
itemsData.filter(i =>
i.Procurement_Category === "Emergency Purchase").length;

const plannedPurchases =
itemsData.filter(i =>
i.Procurement_Category === "Planned Purchase").length;

const approvalRequired =
itemsData.filter(i =>
i.Procurement_Status === "Approval Required").length;

const totalInventoryValue =
itemsData.reduce(
(sum,i)=>sum+Number(i.Inventory_Value_USD||0),0);

const totalProcurementValue =
itemsData.reduce(
(sum,i)=>sum+Number(i.Estimated_Order_Value||0),0);

return [

{json:{KPI:"Total Products",Value:totalProducts}},

{json:{KPI:"Critical Products",Value:criticalProducts}},

{json:{KPI:"High Priority Products",Value:highProducts}},

{json:{KPI:"Stockout Within 7 Days",Value:stockout7}},

